pub fn exit_with_signal(&self, signal: usize) {
        info!("Process {} terminated by signal {}", self.task_id, signal);
        info!("LTP_SIGNAL_DEBUG: Process {} being terminated by signal {}", self.task_id, signal);

        // 检查信号是否应该产生core dump
        let should_dump_core = match signal {
            3 | 4 | 5 | 6 | 8 | 10 | 11 => true, // SIGQUIT, SIGILL, SIGTRAP, SIGABRT, SIGFPE, SIGBUS, SIGSEGV
            _ => false,
        };

        // 特别关注abort()相关的测试
        if signal == 6 {  // SIGABRT/SIGIOT
            info!("LTP_ABORT_SIGNAL_DEBUG: abort() signal (SIGABRT/SIGIOT) received in process {}, will dump core: {}", 
                  self.task_id, should_dump_core);
        }

        // 标记进程是被信号杀死的
        {
            let mut pcb = self.pcb.lock();
            pcb.exit_signal = Some(signal);
            pcb.exit_code = Some(0); // 被信号杀死时，退出码设为0
            pcb.core_dumped = should_dump_core;

            if should_dump_core {
                info!("Process {} will dump core due to signal {}", self.task_id, signal);
                info!("LTP_CORE_DEBUG: Process {} will dump core due to signal {}", self.task_id, signal);
            }
        }

        // 执行正常的退出清理
        self.exit(0);
    }

pub fn cow_fork(self: Arc<Self>) -> Arc<Self> {
        let parent_task: Arc<UserTask> = self.clone();
        let work_dir = parent_task.clone().pcb.lock().curr_dir.path_buf();
        let new_task = Self::new(Arc::downgrade(&parent_task), work_dir);
        let mut new_tcb_writer = new_task.tcb.write();

        // 克隆基本信息
        let mut new_pcb = new_task.pcb.lock();
        let mut pcb = self.pcb.lock();
        new_pcb.fd_table.0 = pcb.fd_table.0.clone();
        new_pcb.heap = pcb.heap;
        new_pcb.curr_dir = pcb.curr_dir.clone();
        new_pcb.shms = pcb.shms.clone();
        pcb.children.push(new_task.clone());
        drop(new_pcb);

        new_tcb_writer.cx = self.tcb.read().cx.clone();
        new_tcb_writer.cx[TrapFrameArgs::RET] = 0;
        drop(new_tcb_writer);

        pcb.memset.iter().for_each(|area| {
            let map_area = area.clone();

            // 禁用内存空隙填补逻辑 - 这会导致段错误
            // 这个逻辑创建了没有实际物理页面映射的内存区域
            // 当程序访问这些区域时会触发SIGSEGV
            #[cfg(never)]  // 完全禁用这个逻辑
            #[cfg(not(target_arch = "loongarch64"))]
            {
                // 检查是否存在内存空隙，如果存在则填补
                if let Some(next_area) = pcb
                    .memset
                    .iter()
                    .find(|next| next.start > area.start + area.len)
                {
                    let gap_start = area.start + area.len;
                    let gap_end = next_area.start;

                    if gap_end - gap_start > 0 && gap_end - gap_start < 0x10000 {
                        // 只处理小于64KB的空隙
                        warn!(
                            "Detected memory gap: {:#x} - {:#x}, filling it",
                            gap_start, gap_end
                        );

                        // 创建一个新的内存区域来填补空隙
                        let gap_area = MemArea {
                            mtype: MemType::Mmap,
                            mtrackers: Vec::new(),
                            file: area.file.clone(), // 使用相同的文件引用
                            offset: area.offset + area.len,
                            start: gap_start,
                            len: gap_end - gap_start,
                        };

                        new_task.pcb.lock().memset.push(gap_area);
                    }
                }
            }

            // 根据内存区域类型选择映射权限：
            //   - 对于 Shared / ShareFile ，必须带写权限，避免 fork 后写入触发 COW
            //   - 其它区域沿用只读 + 可执行，后续由写时复制处理
            let map_flags = match map_area.mtype {
                MemType::Shared | MemType::ShareFile => MappingFlags::URWX,
                _ => MappingFlags::URX,
            };

            map_area.mtrackers.iter().for_each(|mtracker| {
                new_task.map(mtracker.tracker.0, mtracker.vaddr, map_flags);
                self.map(mtracker.tracker.0, mtracker.vaddr, map_flags);
            });
            new_task.pcb.lock().memset.push(map_area);
        });

        // 处理共享内存
        pcb.shms.iter().for_each(|shm| {
            shm.mem
                .trackers
                .iter()
                .enumerate()
                .for_each(|(i, tracker)| {
                    new_task.map(
                        tracker.0,
                        va!(shm.start + i * PAGE_SIZE),
                        MappingFlags::URWX,
                    );
                });
        });

        drop(pcb);
        new_task
    }

    #[inline]

pub fn thread_clone(self: Arc<Self>) -> Arc<Self> {
        let parent_tcb = self.tcb.read();
        let task_id = task_id_alloc();

        let tcb = RwLock::new(ThreadControlBlock {
            cx: parent_tcb.cx.clone(),
            sigmask: parent_tcb.sigmask.clone(),
            clear_child_tid: 0,
            set_child_tid: 0,
            signal: SignalList::new(),
            signal_queue: [0; REAL_TIME_SIGNAL_NUM],
            exit_signal: 0,
            thread_exit_code: Option::None,
            robust_list_head: 0,            // 新线程不继承父线程的 robust list
            robust_list_len: 0,             // 新线程不继承父线程的 robust list
        });

        tcb.write().cx[TrapFrameArgs::RET] = 0;
        drop(parent_tcb);

        let new_task = Arc::new(Self {
            page_table: self.page_table.clone(),
            task_id,
            process_id: self.process_id,  // 重要：保持相同的process_id
            parent: RwLock::new(self.parent.read().clone()),
            pcb: self.pcb.clone(),       // 重要：共享PCB
            tcb,
        });

        // 维护线程列表
        {
            let mut pcb = self.pcb.lock();
            // 清理死亡的线程引用
            pcb.threads.retain(|weak_ref| weak_ref.strong_count() > 0);
            // 添加新线程
            pcb.threads.push(Arc::downgrade(&new_task));

            warn!("Thread created: task_id={}, process_id={}, total_active_threads={}", 
                new_task.task_id, new_task.process_id, pcb.threads.len());
        }

        new_task
    }

pub fn push_str(&self, str: &str) -> usize {
        self.push_arr(str.as_bytes())
    }

pub fn push_arr(&self, buffer: &[u8]) -> usize {
        let mut tcb = self.tcb.write();

        const ULEN: usize = size_of::<usize>();
        let len = buffer.len();
        let sp = tcb.cx[TrapFrameArgs::SP] - alignup(len + 1, ULEN);
        VirtAddr::from(sp)
            .slice_mut_with_len(len)
            .copy_from_slice(buffer);
        tcb.cx[TrapFrameArgs::SP] = sp;
        sp
    }

pub fn push_num(&self, num: usize) -> usize {
        let mut tcb = self.tcb.write();

        const ULEN: usize = size_of::<usize>();
        let sp = tcb.cx[TrapFrameArgs::SP] - ULEN;

        *VirtAddr::from(sp).get_mut_ref() = num;
        tcb.cx[TrapFrameArgs::SP] = sp;
        sp
    }

pub fn get_fd(&self, index: usize) -> Option<Arc<File>> {
        let pcb = self.pcb.lock();
        match index >= pcb.rlimits[7] {
            true => None,
            false => pcb.fd_table.0[index].clone(),
        }
    }

pub fn set_fd(&self, index: usize, value: Arc<File>) {
        let mut pcb = self.pcb.lock();
        match index >= pcb.rlimits[7] {
            true => {}
            false => pcb.fd_table.0[index] = Some(value),
        }
    }

pub fn clear_fd(&self, index: usize) {
        let mut pcb = self.pcb.lock();
        match index >= pcb.fd_table.len() {
            true => {}
            false => pcb.fd_table.0[index] = None,
        }
    }

pub fn alloc_fd(&self) -> Option<usize> {
        let mut pcb = self.pcb.lock();
        let index = pcb
            .fd_table
            .0
            .iter()
            .enumerate()
            .find(|(i, x)| x.is_none() && *i < pcb.rlimits[7])
            .map(|(i, _)| i);
        if index.is_none() && pcb.fd_table.0.len() < pcb.rlimits[7] {
            pcb.fd_table.0.push(None);
            Some(pcb.fd_table.0.len() - 1)
        } else {
            index
        }
    }

pub fn fd_open(&self, fd: isize, filename: &str, flags: OpenFlags) -> VfsResult<File> {
        let path = self.fd_resolve(fd, filename)?;
        File::open(path, flags)
    }

    #[inline]

pub fn fd_resolve(&self, fd: isize, filename: &str) -> VfsResult<PathBuf> {
        if filename.starts_with("/") {
            Ok(filename.into())
        } else {
            let parent = match fd {
                AT_CWD => self.pcb.lock().curr_dir.clone(),
                _ => self
                    .pcb
                    .lock()
                    .fd_table
                    .get(fd as usize)
                    .cloned()
                    .flatten()
                    .ok_or(Errno::EBADF)?,
            };
            Ok(parent.path_buf().join(filename))
        }
    }

pub fn get_elf_segment_for_addr(
        &self,
        vaddr: VirtAddr,
    ) -> Option<(Arc<dyn INodeInterface>, usize, usize)> {
        let pcb = self.pcb.lock();

        warn!(
            "get_elf_segment_for_addr: task_id={}, process_id={}, searching for vaddr={:#x}",
            self.task_id,
            self.process_id,
            vaddr.raw()
        );
        warn!("Total memory areas: {}", pcb.memset.len());

        // 只在非 LoongArch 架构下进行内存空隙检查，避免干扰 LoongArch 系统调用
        #[cfg(not(target_arch = "loongarch64"))]
        {
            // 检查是否存在内存空隙
            for i in 0..pcb.memset.len() {
                if i + 1 < pcb.memset.len() {
                    let current = &pcb.memset[i];
                    let next = &pcb.memset[i + 1];
                    let gap_start = current.start + current.len;
                    let gap_end = next.start;

                    if gap_end > gap_start && vaddr.raw() >= gap_start && vaddr.raw() < gap_end {
                        warn!(
                            "Address {:#x} falls in memory gap between areas {} and {}",
                            vaddr.raw(),
                            i,
                            i + 1
                        );
                        warn!("Gap: {:#x} - {:#x}", gap_start, gap_end);

                        // 尝试从前一个区域的文件中读取
                        if let Some(file) = &current.file {
                            let file_offset = current.offset + (vaddr.raw() - current.start);
                            warn!(
                                "Attempting to use file from previous area with offset {:#x}",
                                file_offset
                            );
                            return Some((file.clone(), file_offset, gap_end - gap_start));
                        }
                    }
                }
            }
        }

        warn!(
            "get_elf_segment_for_addr: task_id={}, process_id={}, searching for vaddr={:#x}",
            self.task_id,
            self.process_id,
            vaddr.raw()
        );
        warn!("Total memory areas: {}", pcb.memset.len());

        // 查找包含该地址且有文件引用的内存区域
        for (i, area) in pcb.memset.iter().enumerate() {
            warn!("  Area {}: start={:#x}, end={:#x}, len={:#x}, mtype={:?}, has_file={}, contains={}", 
                i, area.start, area.start + area.len, area.len, area.mtype, area.file.is_some(), area.contains(vaddr.raw()));

            if area.contains(vaddr.raw()) && area.file.is_some() {
                let file = area.file.as_ref().unwrap();

                // 改进偏移计算
                let page_aligned_vaddr = vaddr.floor().raw();
                let file_offset = area.offset + (page_aligned_vaddr - area.start);

                warn!("get_elf_segment_for_addr: FOUND! vaddr={:#x}, area_start={:#x}, area_offset={:#x}, calculated_offset={:#x}", 
                    vaddr.raw(), area.start, area.offset, file_offset);

                return Some((file.clone(), file_offset, area.len));
            }
        }

        warn!(
            "get_elf_segment_for_addr: NOT FOUND for vaddr={:#x}",
            vaddr.raw()
        );
        None
    }

    /// 简单的资源清理函数

pub fn simple_cleanup(&self) {
        log::info!("Simple resource cleanup for task {}", self.task_id);

        // 内存屏障
        core::sync::atomic::fence(core::sync::atomic::Ordering::SeqCst);

        // 清理文件描述符
        {
            let mut pcb = self.pcb.lock();
            for i in 0..pcb.fd_table.len() {
                if pcb.fd_table[i].is_some() {
                    pcb.fd_table[i] = None;
                }
            }
        }

        // 短暂等待
        for _ in 0..50000 {
            core::hint::spin_loop();
        }

        log::info!("Simple cleanup completed for task {}", self.task_id);
    }
}

fn before_run(&self) {
        self.page_table.change();
    }

fn get_task_id(&self) -> TaskId {
        self.task_id
    }

fn get_task_type(&self) -> TaskType {
        TaskType::MonolithicTask
    }

    #[inline]

fn exit(&self, exit_code: usize) {
        info!("LTP_EXIT_DEBUG: Process {} exiting with code {}", self.task_id, exit_code);

        warn!("Process exit: task_id={}, process_id={}, exit_code={}, arch={}", 
            self.task_id, self.process_id, exit_code, 
            if cfg!(target_arch = "loongarch64") { "loongarch64" } else { "other" });

        let tcb_writer = self.tcb.write();
        let uaddr = tcb_writer.clear_child_tid;
        if uaddr != 0 {
            debug!("write addr: {:#x}", uaddr);
            if let Some((addr, _)) = self.page_table.translate(VirtAddr::from(uaddr)) {
                unsafe {
                    addr.get_mut_ptr::<u32>().write(0);
                }
                futex_wake(self.pcb.lock().futex_table.clone(), uaddr, 1);
            } else {
                warn!("Failed to translate clear_child_tid address: {:#x}", uaddr);
            }
        }

        let exit_signal = tcb_writer.exit_signal;
        drop(tcb_writer);

        // 改进的进程退出逻辑
        let should_cleanup_process = {
            let mut pcb = self.pcb.lock();

            pcb.exit_code = Some(exit_code);

            pcb.threads.retain(|weak_ref| {
                if let Some(thread) = weak_ref.upgrade() {
                    thread.task_id != self.task_id
                } else {
                    false
                }
            });

            let remaining_threads = pcb.threads.len();
            let is_main_thread = self.task_id == self.process_id;

            // 只有主线程退出且没有其他线程时才清理
            is_main_thread && remaining_threads == 0
        };

        if should_cleanup_process {
            warn!("Thread exit triggering process cleanup for process_id={}", self.process_id);
            let mut pcb = self.pcb.lock();
            pcb.memset.clear();
            pcb.fd_table.clear();
            pcb.children.clear();
            pcb.exit_code = Some(exit_code);

            if let Some(parent) = self.parent.read().upgrade() {
                if exit_signal != 0 {
                    parent
                        .tcb
                        .write()
                        .signal
                        .add_signal(SignalFlags::from_num(exit_signal as _));
                } else {
                    parent.tcb.write().signal.add_signal(SignalFlags::SIGCHLD);
                }
            }
        } else {
            warn!("Thread exit: task_id={} exited, but process continues", self.task_id);
        }
    }

    #[inline]

fn exit_code(&self) -> Option<usize> {
        self.pcb.lock().exit_code
    }
}

fn try_from(version: u32) -> Result<Self, Self::Error> {
        match version {
            LEGACY_VERSION => Ok(Self::Legacy),
            MODERN_VERSION => Ok(Self::Modern),
            _ => Err(MmioError::UnsupportedVersion(version)),
        }
    }
}

fn from(version: MmioVersion) -> Self {
        match version {
            MmioVersion::Legacy => LEGACY_VERSION,
            MmioVersion::Modern => MODERN_VERSION,
        }
    }
}

/// An error encountered initialising a VirtIO MMIO transport.
#[derive(Clone, Debug, Eq, Error, PartialEq)]
pub enum MmioError {
    /// The header doesn't start with the expected magic value 0x74726976.
    #[error("Invalid magic value {0:#010x} (expected 0x74726976)")]
    BadMagic(u32),
    /// The header reports a version number that is neither 1 (legacy) nor 2 (modern).
    #[error("Unsupported Virtio MMIO version {0}")]
    UnsupportedVersion(u32),
    /// The header reports a device ID of 0.
    #[error("Device ID was zero")]
    ZeroDeviceId,
}

/// MMIO Device Register Interface, both legacy and modern.
///
/// Ref: 4.2.2 MMIO Device Register Layout and 4.2.4 Legacy interface
#[repr(C)]

pub struct VirtIOHeader {
    /// Magic value
    magic: ReadOnly<u32>,

    /// Device version number
    ///
    /// Legacy device returns value 0x1.
    version: ReadOnly<u32>,

    /// Virtio Subsystem Device ID
    device_id: ReadOnly<u32>,

    /// Virtio Subsystem Vendor ID
    vendor_id: ReadOnly<u32>,

    /// Flags representing features the device supports
    device_features: ReadOnly<u32>,

    /// Device (host) features word selection
    device_features_sel: WriteOnly<u32>,

    /// Reserved
    __r1: [ReadOnly<u32>; 2],

    /// Flags representing device features understood and activated by the driver
    driver_features: WriteOnly<u32>,

    /// Activated (guest) features word selection
    driver_features_sel: WriteOnly<u32>,

    /// Guest page size
    ///
    /// The driver writes the guest page size in bytes to the register during
    /// initialization, before any queues are used. This value should be a
    /// power of 2 and is used by the device to calculate the Guest address
    /// of the first queue page (see QueuePFN).
    legacy_guest_page_size: WriteOnly<u32>,

    /// Reserved
    __r2: ReadOnly<u32>,

    /// Virtual queue index
    ///
    /// Writing to this register selects the virtual queue that the following
    /// operations on the QueueNumMax, QueueNum, QueueAlign and QueuePFN
    /// registers apply to. The index number of the first queue is zero (0x0).
    queue_sel: WriteOnly<u32>,

    /// Maximum virtual queue size
    ///
    /// Reading from the register returns the maximum size of the queue the
    /// device is ready to process or zero (0x0) if the queue is not available.
    /// This applies to the queue selected by writing to QueueSel and is
    /// allowed only when QueuePFN is set to zero (0x0), so when the queue is
    /// not actively used.
    queue_num_max: ReadOnly<u32>,

    /// Virtual queue size
    ///
    /// Queue size is the number of elements in the queue. Writing to this
    /// register notifies the device what size of the queue the driver will use.
    /// This applies to the queue selected by writing to QueueSel.
    queue_num: WriteOnly<u32>,

    /// Used Ring alignment in the virtual queue
    ///
    /// Writing to this register notifies the device about alignment boundary
    /// of the Used Ring in bytes. This value should be a power of 2 and
    /// applies to the queue selected by writing to QueueSel.
    legacy_queue_align: WriteOnly<u32>,

    /// Guest physical page number of the virtual queue
    ///
    /// Writing to this register notifies the device about location of the
    /// virtual queue in the Guest’s physical address space. This value is
    /// the index number of a page starting with the queue Descriptor Table.
    /// Value zero (0x0) means physical address zero (0x00000000) and is illegal.
    /// When the driver stops using the queue it writes zero (0x0) to this
    /// register. Reading from this register returns the currently used page
    /// number of the queue, therefore a value other than zero (0x0) means that
    /// the queue is in use. Both read and write accesses apply to the queue
    /// selected by writing to QueueSel.
    legacy_queue_pfn: Volatile<u32>,

    /// new interface only
    queue_ready: Volatile<u32>,

    /// Reserved
    __r3: [ReadOnly<u32>; 2],

    /// Queue notifier
    queue_notify: WriteOnly<u32>,

    /// Reserved
    __r4: [ReadOnly<u32>; 3],

    /// Interrupt status
    interrupt_status: ReadOnly<u32>,

    /// Interrupt acknowledge
    interrupt_ack: WriteOnly<u32>,

    /// Reserved
    __r5: [ReadOnly<u32>; 2],

    /// Device status
    ///
    /// Reading from this register returns the current device status flags.
    /// Writing non-zero values to this register sets the status flags,
    /// indicating the OS/driver progress. Writing zero (0x0) to this register
    /// triggers a device reset. The device sets QueuePFN to zero (0x0) for
    /// all queues in the device. Also see 3.1 Device Initialization.
    status: Volatile<DeviceStatus>,

    /// Reserved
    __r6: [ReadOnly<u32>; 3],

    // new interface only since here
    queue_desc_low: WriteOnly<u32>,
    queue_desc_high: WriteOnly<u32>,

    /// Reserved
    __r7: [ReadOnly<u32>; 2],

    queue_driver_low: WriteOnly<u32>,
    queue_driver_high: WriteOnly<u32>,

    /// Reserved
    __r8: [ReadOnly<u32>; 2],

    queue_device_low: WriteOnly<u32>,
    queue_device_high: WriteOnly<u32>,

    /// Reserved
    __r9: [ReadOnly<u32>; 21],

    config_generation: ReadOnly<u32>,
}

impl VirtIOHeader {
    /// Constructs a fake VirtIO header for use in unit tests.
    #[cfg(test)]

pub struct MmioTransport {
    header: NonNull<VirtIOHeader>,
    version: MmioVersion,
}

impl MmioTransport {
    /// Constructs a new VirtIO MMIO transport, or returns an error if the header reports an
    /// unsupported version.
    ///
    /// # Safety
    /// `header` must point to a properly aligned valid VirtIO MMIO region, which must remain valid
    /// for the lifetime of the transport that is returned.
    pub unsafe fn new(header: NonNull<VirtIOHeader>) -> Result<Self, MmioError> {
        let magic = volread!(header, magic);
        if magic != MAGIC_VALUE {
            return Err(MmioError::BadMagic(magic));
        }
        if volread!(header, device_id) == 0 {
            return Err(MmioError::ZeroDeviceId);
        }
        let version = volread!(header, version).try_into()?;
        Ok(Self { header, version })
    }

    /// Gets the version of the VirtIO MMIO transport.

pub fn version(&self) -> MmioVersion {
        self.version
    }

    /// Gets the vendor ID.

pub fn vendor_id(&self) -> u32 {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe { volread!(self.header, vendor_id) }
    }
}

// SAFETY: `header` is only used for MMIO, which can happen from any thread or CPU core.
unsafe impl Send for MmioTransport {}

// SAFETY: `&MmioTransport` only allows MMIO reads or getting the config space, both of which are
// fine to happen concurrently on different CPU cores.
unsafe impl Sync for MmioTransport {}

fn device_type(&self) -> DeviceType {
        // Safe because self.header points to a valid VirtIO MMIO region.
        let device_id = unsafe { volread!(self.header, device_id) };
        device_id.into()
    }

fn read_device_features(&mut self) -> u64 {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, device_features_sel, 0); // device features [0, 32)
            let mut device_features_bits = volread!(self.header, device_features).into();
            volwrite!(self.header, device_features_sel, 1); // device features [32, 64)
            device_features_bits += (volread!(self.header, device_features) as u64) << 32;
            device_features_bits
        }
    }

fn write_driver_features(&mut self, driver_features: u64) {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, driver_features_sel, 0); // driver features [0, 32)
            volwrite!(self.header, driver_features, driver_features as u32);
            volwrite!(self.header, driver_features_sel, 1); // driver features [32, 64)
            volwrite!(self.header, driver_features, (driver_features >> 32) as u32);
        }
    }

fn max_queue_size(&mut self, queue: u16) -> u32 {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, queue_sel, queue.into());
            volread!(self.header, queue_num_max)
        }
    }

fn notify(&mut self, queue: u16) {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, queue_notify, queue.into());
        }
    }

fn get_status(&self) -> DeviceStatus {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe { volread!(self.header, status) }
    }

fn set_status(&mut self, status: DeviceStatus) {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, status, status);
        }
    }

fn set_guest_page_size(&mut self, guest_page_size: u32) {
        match self.version {
            MmioVersion::Legacy => {
                // Safe because self.header points to a valid VirtIO MMIO region.
                unsafe {
                    volwrite!(self.header, legacy_guest_page_size, guest_page_size);
                }
            }
            MmioVersion::Modern => {
                // No-op, modern devices don't care.
            }
        }
    }

fn requires_legacy_layout(&self) -> bool {
        match self.version {
            MmioVersion::Legacy => true,
            MmioVersion::Modern => false,
        }
    }

fn queue_set(
        &mut self,
        queue: u16,
        size: u32,
        descriptors: PhysAddr,
        driver_area: PhysAddr,
        device_area: PhysAddr,
    ) {
        match self.version {
            MmioVersion::Legacy => {
                assert_eq!(
                    driver_area - descriptors,
                    size_of::<Descriptor>() * size as usize
                );
                assert_eq!(
                    device_area - descriptors,
                    align_up(
                        size_of::<Descriptor>() * size as usize
                            + size_of::<u16>() * (size as usize + 3)
                    )
                );
                let align = PAGE_SIZE as u32;
                let pfn = (descriptors / PAGE_SIZE) as u32;
                assert_eq!(pfn as usize * PAGE_SIZE, descriptors);
                // Safe because self.header points to a valid VirtIO MMIO region.
                unsafe {
                    volwrite!(self.header, queue_sel, queue.into());
                    volwrite!(self.header, queue_num, size);
                    volwrite!(self.header, legacy_queue_align, align);
                    volwrite!(self.header, legacy_queue_pfn, pfn);
                }
            }
            MmioVersion::Modern => {
                // Safe because self.header points to a valid VirtIO MMIO region.
                unsafe {
                    volwrite!(self.header, queue_sel, queue.into());
                    volwrite!(self.header, queue_num, size);
                    volwrite!(self.header, queue_desc_low, descriptors as u32);
                    volwrite!(self.header, queue_desc_high, (descriptors >> 32) as u32);
                    volwrite!(self.header, queue_driver_low, driver_area as u32);
                    volwrite!(self.header, queue_driver_high, (driver_area >> 32) as u32);
                    volwrite!(self.header, queue_device_low, device_area as u32);
                    volwrite!(self.header, queue_device_high, (device_area >> 32) as u32);
                    volwrite!(self.header, queue_ready, 1);
                }
            }
        }
    }

fn queue_unset(&mut self, queue: u16) {
        match self.version {
            MmioVersion::Legacy => {
                // Safe because self.header points to a valid VirtIO MMIO region.
                unsafe {
                    volwrite!(self.header, queue_sel, queue.into());
                    volwrite!(self.header, queue_num, 0);
                    volwrite!(self.header, legacy_queue_align, 0);
                    volwrite!(self.header, legacy_queue_pfn, 0);
                }
            }
            MmioVersion::Modern => {
                // Safe because self.header points to a valid VirtIO MMIO region.
                unsafe {
                    volwrite!(self.header, queue_sel, queue.into());

                    volwrite!(self.header, queue_ready, 0);
                    // Wait until we read the same value back, to ensure synchronisation (see 4.2.2.2).
                    while volread!(self.header, queue_ready) != 0 {}

                    volwrite!(self.header, queue_num, 0);
                    volwrite!(self.header, queue_desc_low, 0);
                    volwrite!(self.header, queue_desc_high, 0);
                    volwrite!(self.header, queue_driver_low, 0);
                    volwrite!(self.header, queue_driver_high, 0);
                    volwrite!(self.header, queue_device_low, 0);
                    volwrite!(self.header, queue_device_high, 0);
                }
            }
        }
    }

fn queue_used(&mut self, queue: u16) -> bool {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            volwrite!(self.header, queue_sel, queue.into());
            match self.version {
                MmioVersion::Legacy => volread!(self.header, legacy_queue_pfn) != 0,
                MmioVersion::Modern => volread!(self.header, queue_ready) != 0,
            }
        }
    }

fn ack_interrupt(&mut self) -> bool {
        // Safe because self.header points to a valid VirtIO MMIO region.
        unsafe {
            let interrupt = volread!(self.header, interrupt_status);
            if interrupt != 0 {
                volwrite!(self.header, interrupt_ack, interrupt);
                true
            } else {
                false
            }
        }
    }

    fn read_config_space<T>(&self, offset: usize) -> Result<T, Error> {
        assert!(align_of::<T>() <= 4,
            "Driver expected config space alignment of {} bytes, but VirtIO only guarantees 4 byte alignment.",
            align_of::<T>());
        assert!(offset % align_of::<T>() == 0);

        // SAFETY: The caller of `MmioTransport::new` guaranteed that the header pointer was valid,
        // which includes the config space.
        unsafe {
            Ok(self
                .header
                .cast::<T>()
                .byte_add(CONFIG_SPACE_OFFSET)
                .byte_add(offset)
                .read_volatile())
        }
    }

    fn write_config_space<T>(&mut self, offset: usize, value: T) -> Result<(), Error> {
        assert!(align_of::<T>() <= 4,
            "Driver expected config space alignment of {} bytes, but VirtIO only guarantees 4 byte alignment.",
            align_of::<T>());
        assert!(offset % align_of::<T>() == 0);

        // SAFETY: The caller of `MmioTransport::new` guaranteed that the header pointer was valid,
        // which includes the config space.
        unsafe {
            self.header
                .cast::<T>()
                .byte_add(CONFIG_SPACE_OFFSET)
                .byte_add(offset)
                .write_volatile(value);
        }
        Ok(())
    }
}

fn drop(&mut self) {
        // Reset the device when the transport is dropped.
        self.set_status(DeviceStatus::empty())
    }
}

pub async fn sys_dup(&self, fd: usize) -> SysResult {
        debug!("sys_dup3 @ fd_src: {}", fd);
        let fd_dst = self.task.alloc_fd().ok_or(Errno::EMFILE)?;
        self.sys_dup3(fd, fd_dst).await
    }

pub async fn sys_dup3(&self, fd_src: usize, fd_dst: usize) -> SysResult {
        debug!("sys_dup3 @ fd_src: {}, fd_dst: {}", fd_src, fd_dst);
        let file = self.task.get_fd(fd_src).ok_or(Errno::EBADF)?;
        self.task.set_fd(fd_dst, file);
        Ok(fd_dst)
    }

