        debug!(
            "sys_fstatat @ dir_fd: {}, path:{}, stat_ptr: {}",
            dir_fd as isize, path, stat_ptr
        );
        let stat = stat_ptr.get_mut();

        self.task
            .fd_open(dir_fd, path, OpenFlags::O_RDONLY)?
            .stat(stat)?;
        stat.mode |= StatMode::OWNER_MASK;
        Ok(0)
    }

