    /// linkat系统调用 - 创建硬链接
    /// LTP测试可能使用硬链接来管理测试文件

pub async fn sys_linkat(
        &self, 
        olddirfd: isize, 
        oldpath: UserRef<u8>, 
        newdirfd: isize, 
        newpath: UserRef<u8>, 
        flags: usize
    ) -> SysResult {
        let oldpath = oldpath.get_cstr().map_err(|_| Errno::EINVAL)?;
        let newpath = newpath.get_cstr().map_err(|_| Errno::EINVAL)?;

        debug!("sys_linkat @ olddirfd: {}, oldpath: {}, newdirfd: {}, newpath: {}, flags: {:#x}", 
               olddirfd, oldpath, newdirfd, newpath, flags);

        warn!("LINKAT_DEBUG: LTP creating hard link {} -> {} for test file management", newpath, oldpath);

        // 构建源文件和目标文件的完整路径
        let src_path = if olddirfd == AT_FDCWD {
            // 相对路径，从当前工作目录开始
            let cwd = self.task.pcb.lock().curr_dir.path();
            if oldpath.starts_with('/') {
                oldpath.to_string()
            } else {
                format!("{}/{}", cwd, oldpath)
            }
        } else {
            // 从指定的文件描述符开始
            let old_file = self.task.get_fd(olddirfd as usize)
                .ok_or(Errno::EBADF)?;
            // 简化处理：直接使用oldpath
            oldpath.to_string()
        };

        let target_path = if newdirfd == AT_FDCWD {
            // 相对路径，从当前工作目录开始
            let cwd = self.task.pcb.lock().curr_dir.path();
            if newpath.starts_with('/') {
                newpath.to_string()
            } else {
                format!("{}/{}", cwd, newpath)
            }
        } else {
            // 从指定的文件描述符开始
            let new_file = self.task.get_fd(newdirfd as usize)
                .ok_or(Errno::EBADF)?;
            // 简化处理：直接使用newpath
            newpath.to_string()
        };

        // 检查源文件是否存在且不是目录
        let src_file = match File::open(PathBuf::from(src_path.as_str()), OpenFlags::O_RDONLY) {
            Ok(file) => file,
            Err(e) => {
                warn!("LINKAT_DEBUG: Failed to open source file {}: {:?}", src_path, e);
                return Err(e);
            }
        };

        let mut src_stat = Stat::default();
        src_file.stat(&mut src_stat)?;

        if src_stat.mode.contains(StatMode::DIR) {
            warn!("LINKAT_DEBUG: Cannot create hard link to directory {}", src_path);
            return Err(Errno::EPERM);
        }

        // 检查目标文件是否已存在
        if let Ok(_) = File::open(PathBuf::from(target_path.as_str()), OpenFlags::O_RDONLY) {
            warn!("LINKAT_DEBUG: Target file {} already exists", target_path);
            return Err(Errno::EEXIST);
        }

        // 获取目标文件的目录路径和文件名
        let target_dir_path = if let Some(last_slash) = target_path.rfind('/') {
            if last_slash == 0 {
                "/".to_string()
            } else {
                target_path[..last_slash].to_string()
            }
        } else {
            ".".to_string()
        };

        let target_filename = if let Some(last_slash) = target_path.rfind('/') {
            target_path[last_slash + 1..].to_string()
        } else {
            target_path.clone()
        };

        // 打开目标目录
        let target_dir = match File::open(PathBuf::from(target_dir_path.as_str()), OpenFlags::O_DIRECTORY) {
            Ok(dir) => dir,
            Err(e) => {
                warn!("LINKAT_DEBUG: Failed to open target directory {}: {:?}", target_dir_path, e);
                return Err(e);
            }
        };

        // 创建硬链接
        match target_dir.link(&target_filename, src_file.get_bare_file()) {
            Ok(()) => {
                warn!("LINKAT_DEBUG: Successfully created hard link {} -> {}", target_path, src_path);
                Ok(0)
            }
            Err(e) => {
                warn!("LINKAT_DEBUG: Failed to create hard link {} -> {}: {:?}", target_path, src_path, e);
                Err(e)
            }
        }
    }

