pub struct Semaphore {
    pub key: usize,
    pub nsems: usize,
    pub values: Vec<i32>,
}

pub fn new(key: usize, nsems: usize) -> Self {
        Self {
            key,
            nsems,
            values: vec![0; nsems],
        }
    }
}

// 信号量全局表
